#include <stdio.h>

void reverseString(char str[]) {
    int len = 0, i;
    while (str[len] != '\0') len++;
    for (i = 0; i < len / 2; i++) {
        char temp = str[i];
        str[i] = str[len - i - 1];
        str[len - i - 1] = temp;
    }
}

