#include <stdio.h>

typedef struct {
    unsigned int error_code;
    unsigned int address_valid : 1;
    unsigned int write_operation : 1;
    unsigned int cache_hit : 1;
    unsigned int cache_level : 3;
    unsigned int error_type : 4;
    unsigned int address : 24;
} memory_error_t;

memory_error_t parse_memory_error(unsigned int error_code) {
    memory_error_t error;
    error.error_code = error_code;
    error.address_valid = (error_code & 0x80000000) >> 31;
    error.write_operation = (error_code & 0x40000000) >> 30;
    error.cache_hit = (error_code & 0x20000000) >> 29;
    error.cache_level = (error_code & 0x18000000) >> 27;
    error.error_type = (error_code & 0x07000000) >> 24;
    error.address = error_code & 0x00FFFFFF;
    return error;
}

int main() {
    unsigned int error_code = 0x80000000;
    memory_error_t error = parse_memory_error(error_code);
    printf("Error code: 0x%08X\n", error.error_code);
    printf("Address valid: %d\n", error.address_valid);
    printf("Write operation: %d\n", error.write_operation);
    printf("Cache hit: %d\n", error.cache_hit);
    printf("Cache level: %d\n", error.cache_level);
    printf("Error type: %d\n", error.error_type);
    printf("Address: 0x%06X\n", error.address);
    return 0;
}
