typedef struct Node {
    int data;
    struct Node *next;
} Node;

Node *createStack() {
    return NULL;
}

Node *push(Node *stack, int data) {
    Node *newNode = (Node *)malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = stack;
    return newNode;
}

Node *pop(Node *stack) {
    if (stack == NULL) {
        return NULL;
    }
    Node *topNode = stack;
    stack = stack->next;
    free(topNode);
    return stack;
}

int top(Node *stack) {
    if (stack == NULL) {
        return -1;
    }
    return stack->data;
}

int isEmpty(Node *stack) {
    return stack == NULL;
}

