#include <stdio.h>

void countOccurrences(int arr[], int size, int target, int *count) {
    *count = 0;
    for (int i = 0; i < size; i++) {
        if (arr[i] == target) {
            (*count)++;
        }
    }
}

int main() {
    int arr[] = {1, 2, 3, 4, 3, 2, 3};
    int size = sizeof(arr) / sizeof(arr[0]);
    int target = 3, count;

    countOccurrences(arr, size, target, &count);

    printf("The number %d occurs %d times in the array.\n", target, count);
    return 0;
}
